#include <bits/stdc++.h>
using namespace std;

long long n,m,a,c,fir,ans[2][2],base[2][2],tmp[2][2];
int g;

int main(){
    scanf("%lld%lld%lld%lld%lld%d",&m,&a,&c,&fir,&n,&g);
    ans[0][0]=ans[1][1]=1;
    base[0][0]=base[0][1]=1,base[1][1]=a;
    while(n){
        if(n&1){
            for(int i=0;i<2;i++)
                for(int j=0;j<2;j++)
                    tmp[i][j]=ans[i][j],ans[i][j]=0;
            for(int i=0;i<2;i++)
                for(int j=0;j<2;j++)
                    for(int k=0;k<2;k++)
                        ans[i][j]=(ans[i][j]+(__int128)tmp[i][k]*base[k][j])%m;
        }
        for(int i=0;i<2;i++)
            for(int j=0;j<2;j++)
                tmp[i][j]=base[i][j],base[i][j]=0;
        for(int i=0;i<2;i++)
            for(int j=0;j<2;j++)
                for(int k=0;k<2;k++)
                    base[i][j]=(base[i][j]+(__int128)tmp[i][k]*tmp[k][j])%m;
        n>>=1;
    }
    printf("%d",(int)(((__int128)c*ans[0][1]+(__int128)fir*ans[1][1])%m%g));
    return 0;
}
